-- Query: QPkg_Sales_Employee_Studio4
SELECT qPkg_Sales_Employee_Studio2.Studio, qPkg_Sales_Employee_Studio2.UserID, qPkg_Sales_Employee_Studio2.A AS [# A], qPkg_Sales_Employee_Studio3.A AS [$ A], qPkg_Sales_Employee_Studio2.B AS [# B], qPkg_Sales_Employee_Studio3.B AS [$ B], qPkg_Sales_Employee_Studio2.C AS [# C], qPkg_Sales_Employee_Studio3.C AS [$ C], qPkg_Sales_Employee_Studio2.D AS [# D], qPkg_Sales_Employee_Studio3.D AS [$ D], qPkg_Sales_Employee_Studio2.E AS [# E], qPkg_Sales_Employee_Studio3.E AS [$ E], qPkg_Sales_Employee_Studio2.F AS [# F], qPkg_Sales_Employee_Studio3.F AS [$ F], qPkg_Sales_Employee_Studio2.G AS [# G], qPkg_Sales_Employee_Studio3.G AS [$ G], qPkg_Sales_Employee_Studio2.SSP AS [# SSP], qPkg_Sales_Employee_Studio3.SSP AS [$ SSP]
FROM qPkg_Sales_Employee_Studio2 INNER JOIN qPkg_Sales_Employee_Studio3 ON (qPkg_Sales_Employee_Studio2.Studio = qPkg_Sales_Employee_Studio3.Studio) AND (qPkg_Sales_Employee_Studio2.UserID = qPkg_Sales_Employee_Studio3.UserID);

